# Shapes module - demonstrates cross-module inheritance
from types import Color, Point

@abstract
class Shape:
    """Abstract base class for geometric shapes"""
    color: Color

    def __init__(self, color: Color):
        self.color = color

    @abstract
    def area(self) -> float:
        ...

    @virtual
    def describe(self) -> str:
        return "A shape"

class Circle(Shape):
    """Circle class with center point and radius"""
    center: Point
    radius: float

    def __init__(self, center: Point, radius: float, color: Color):
        super().__init__(color)
        self.center = center
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    def draw(self) -> str:
        x_str: str = str(self.center.x)
        y_str: str = str(self.center.y)
        r_str: str = str(self.radius)
        return "Circle at (" + x_str + ", " + y_str + ") radius=" + r_str

    @override
    def describe(self) -> str:
        return "Circle(radius=" + str(self.radius) + ")"

class Rectangle(Shape):
    """Rectangle class with width and height"""
    width: float
    height: float

    def __init__(self, width: float, height: float, color: Color):
        super().__init__(color)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    def draw(self) -> str:
        return "Rectangle " + str(self.width) + "x" + str(self.height)

    @override
    def describe(self) -> str:
        return "Rectangle(" + str(self.width) + "x" + str(self.height) + ")"

