# Utilities module - demonstrates higher-order function usage with imported types
from shapes import Shape, Circle, Rectangle
from types import Color

def total_area(shapes: list[Shape]) -> float:
    """Calculate total area of all shapes"""
    total: float = 0.0
    for s in shapes:
        total += s.area()
    return total

def count_by_color(shapes: list[Shape], color: Color) -> int:
    """Count shapes matching a specific color"""
    count: int = 0
    for s in shapes:
        if s.color == color:
            count += 1
    return count

def render_circle(c: Circle) -> str:
    """Get render description for a circle"""
    return c.draw()

def render_rectangle(r: Rectangle) -> str:
    """Get render description for a rectangle"""
    return r.draw()

def create_circle_at_origin(radius: float, color: Color) -> Circle:
    """Factory function creating a circle at (0, 0)"""
    origin: Point = Point(0.0, 0.0)
    return Circle(origin, radius, color)
